import{_ as t,o,c as a,ag as s}from"./chunks/framework.BqfgOMAh.js";const h=JSON.parse('{"title":"Use NexusFlow from IDEs / Agents","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/mcp.md","filePath":"en/guide/mcp.md"}'),n={name:"en/guide/mcp.md"};function l(i,e,d,r,c,p){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="use-nexusflow-from-ides-agents" tabindex="-1">Use NexusFlow from IDEs / Agents <a class="header-anchor" href="#use-nexusflow-from-ides-agents" aria-label="Permalink to &quot;Use NexusFlow from IDEs / Agents&quot;">​</a></h1><p>NexusFlow 0.2.0 includes an MCP server built into the desktop app. When enabled, Cursor, Claude Code, and other MCP-capable IDEs or agents can connect to NexusFlow and use it as an Unreal Engine automation gateway.</p><p>This is not about connecting external MCP servers into the NexusFlow desktop app. The direction is the opposite: <strong>external IDEs and agents connect to the MCP server exposed by NexusFlow</strong>, then use NexusFlow to operate UE context, Blueprints, Widgets, templates, node search, and supported editor actions.</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li>Let agents in Cursor, Claude Code, or other MCP clients operate UE Blueprints directly.</li><li>Read the current Unreal Editor context, including selected assets, open Blueprints, and connection status.</li><li>Execute constrained Blueprint, Widget, asset, and editor operations through NexusFlow Skills.</li><li>Search UE nodes or reuse Blueprint templates before generating Blueprint logic.</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Before using this workflow, make sure that:</p><ol><li>The NexusFlow desktop app is installed and running.</li><li>MCP mode is enabled in NexusFlow.</li><li>Your MCP client is connected to the MCP endpoint exposed by NexusFlow.</li><li>For UE operations, Unreal Engine is open and the NexusFlow UE plugin is installed and connected.</li></ol><p>If the MCP client cannot connect, open NexusFlow, enable MCP mode, and verify the endpoint configured in the client.</p><h2 id="recommended-companion-nexusflow-skill" tabindex="-1">Recommended Companion: NexusFlow Skill <a class="header-anchor" href="#recommended-companion-nexusflow-skill" aria-label="Permalink to &quot;Recommended Companion: NexusFlow Skill&quot;">​</a></h2><p>For more reliable IDE / Agent usage, install the separately published <a href="https://github.com/maxzhao/nexusflow-skill" target="_blank" rel="noreferrer">NexusFlow Skill</a>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> maxzhao/nexusflow-skill</span></span></code></pre></div><p>It teaches agents how to check the connection, inspect UE context, search and load NexusFlow Skills, and execute actions safely.</p><h2 id="recommended-workflow" tabindex="-1">Recommended Workflow <a class="header-anchor" href="#recommended-workflow" aria-label="Permalink to &quot;Recommended Workflow&quot;">​</a></h2><p>External agents should use the progressive disclosure workflow instead of loading everything at once:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_connection_status</span></span>
<span class="line"><span>  -&gt; get_ue_context</span></span>
<span class="line"><span>  -&gt; search_skills</span></span>
<span class="line"><span>  -&gt; load_skill</span></span>
<span class="line"><span>  -&gt; [load_knowledge]</span></span>
<span class="line"><span>  -&gt; execute_action</span></span></code></pre></div><p>Tool roles:</p><ul><li><code>get_connection_status</code>: call before any UE operation; continue only when <code>connected: true</code>.</li><li><code>get_ue_context</code>: inspect the current Unreal Editor state.</li><li><code>search_skills</code>: search for the most relevant NexusFlow Skill module.</li><li><code>load_skill</code>: load the selected guide, available functions, parameters, and constraints.</li><li><code>load_knowledge</code>: load a specific topic only when needed.</li><li><code>execute_action</code>: execute the function with arguments derived from the loaded guide and knowledge.</li></ul><h2 id="mcp-tools" tabindex="-1">MCP Tools <a class="header-anchor" href="#mcp-tools" aria-label="Permalink to &quot;MCP Tools&quot;">​</a></h2><p>Tool prefixes can vary by MCP client configuration. Always follow the live tool list and schemas shown by your client.</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>get_connection_status</code></td><td>Check whether NexusFlow is connected to UE</td></tr><tr><td><code>get_ue_context</code></td><td>Inspect the current Unreal Editor context</td></tr><tr><td><code>search_skills</code></td><td>Search NexusFlow Skill modules</td></tr><tr><td><code>load_skill</code></td><td>Load a Skill guide and available knowledge topics</td></tr><tr><td><code>load_knowledge</code></td><td>Load a specific knowledge topic for a Skill</td></tr><tr><td><code>execute_action</code></td><td>Execute a Skill function</td></tr><tr><td><code>search_templates</code></td><td>Search reusable Blueprint templates</td></tr><tr><td><code>load_template</code></td><td>Load a complete template definition</td></tr><tr><td><code>search_nodes</code></td><td>Search Blueprint nodes and engine functions</td></tr><tr><td><code>execute_command</code></td><td>Run supported editor or console commands</td></tr><tr><td><code>execute_python_code</code></td><td>Last resort: direct Python execution with explicit confirmation</td></tr></tbody></table><h2 id="safety-tips" tabindex="-1">Safety Tips <a class="header-anchor" href="#safety-tips" aria-label="Permalink to &quot;Safety Tips&quot;">​</a></h2><ul><li>Prefer <code>search_skills</code> / <code>load_skill</code> / <code>execute_action</code>; do not guess UE Python APIs.</li><li>Do not repeatedly load the same Skill, knowledge topic, or template.</li><li>Prefer local, incremental modifications to existing assets; confirm full rewrites or destructive operations first.</li><li>Verify write operations through returned results, readback, compile/save commands, or screenshots.</li><li>Use <code>execute_python_code</code> only as a confirmed last resort.</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./agent-skill">NexusFlow Skill</a>: install the companion Skill so IDEs and agents can use NexusFlow MCP more reliably.</li><li><a href="./blueprint-operations">Blueprint Operations</a>: learn the built-in Blueprint capabilities.</li><li><a href="./widget-skill">Widget Skill</a>: try Widget Blueprint generation and editing.</li></ul>`,25)])])}const m=t(n,[["render",l]]);export{h as __pageData,m as default};
